export function getByCategory(categoryKey) {
  return questions.filter(q => q.category === categoryKey);
}

export function getRandom(categoryKey, count = 5) {
  const pool = getByCategory(categoryKey);
  const shuffled = [...pool].sort(() => Math.random() - 0.5);
  return shuffled.slice(0, count);
}
